<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Bankeinlage vs. JPYSC-Verleihprodukt — Was ist der Unterschied</text>
  <text x="20" y="50" fill="#71717a" font-size="12" font-family="sans-serif">Laut Ankündigung der SBI Group vom 13. Juli 2026; Antragstellung ab 16. Juli</text>
  <text x="180" y="80" fill="#a1a1aa" font-family="sans-serif" font-size="13" font-weight="700" text-anchor="middle">Gewöhnliche Yen-Einlage</text>
  <text x="520" y="80" fill="#fbbf24" font-family="sans-serif" font-size="13" font-weight="700" text-anchor="middle">JPYSC-Verleihprodukt</text>
  <rect x="20" y="94" width="320" height="42" rx="6" fill="#0f1f18" stroke="#15803d"/>
  <text x="180" y="120" fill="#bbf7d0" font-family="sans-serif" font-size="13" text-anchor="middle">0,325%-1% Jahreszins</text>
